import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getDashboardStats, getCategories } from '../api/inventory';

function KPI({ label, value, sub, icon, color }) {
  return (
    <div className="rounded-2xl border border-slate-800 bg-slate-900 p-4 sm:p-5 flex items-start gap-3 sm:gap-4">
      <div className={`flex-shrink-0 w-9 h-9 sm:w-10 sm:h-10 rounded-xl flex items-center justify-center ${color}`}>
        {icon}
      </div>
      <div className="min-w-0">
        <p className="text-xs uppercase tracking-widest text-slate-500 truncate">{label}</p>
        <p className="mt-1 text-xl sm:text-2xl font-semibold text-slate-100 truncate">{value}</p>
        {sub && <p className="mt-0.5 text-xs text-slate-500">{sub}</p>}
      </div>
    </div>
  );
}

function StatusPill({ count }) {
  if (count >= 10) return <span className="inline-flex rounded-full px-2.5 py-0.5 text-xs font-medium bg-emerald-500/15 text-emerald-300">{count}</span>;
  if (count > 0)   return <span className="inline-flex rounded-full px-2.5 py-0.5 text-xs font-medium bg-amber-500/15 text-amber-300">{count}</span>;
  return               <span className="inline-flex rounded-full px-2.5 py-0.5 text-xs font-medium bg-rose-500/15 text-rose-300">{count}</span>;
}

export default function Dashboard() {
  const [stats, setStats]           = useState(null);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading]       = useState(true);

  useEffect(() => {
    Promise.all([getDashboardStats(), getCategories()])
      .then(([s, c]) => { setStats(s); setCategories(c); })
      .finally(() => setLoading(false));
  }, []);

  const catName = (id) => categories.find((c) => c.id === id)?.name ?? '—';

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6 sm:space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-xl sm:text-2xl font-semibold text-slate-100">Dashboard</h1>
        <p className="text-sm text-slate-500 mt-1">Overview of your inventory and assets</p>
      </div>

      {/* KPI Cards — 1 col on xs, 2 on sm, 4 on lg */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">
        <KPI
          label="Total Items"
          value={stats.totalItems}
          sub="unique SKUs"
          color="bg-cyan-500/15 text-cyan-400"
          icon={<svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"/></svg>}
        />
        <KPI
          label="Total Quantity"
          value={stats.totalQuantity.toLocaleString()}
          sub="units in stock"
          color="bg-violet-500/15 text-violet-400"
          icon={<svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z"/></svg>}
        />
        <KPI
          label="Low Stock"
          value={stats.lowStockCount}
          sub="items need restock"
          color="bg-rose-500/15 text-rose-400"
          icon={<svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"/></svg>}
        />
        <KPI
          label="Total Value"
          value={`$${stats.totalValue.toLocaleString('en-US', { maximumFractionDigits: 0 })}`}
          sub="inventory worth"
          color="bg-emerald-500/15 text-emerald-400"
          icon={<svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>}
        />
      </div>

      {/* Two-column section — stacks on mobile */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6">
        {/* Recent Items */}
        <div className="lg:col-span-2 rounded-2xl border border-slate-800 bg-slate-900 overflow-hidden">
          <div className="flex items-center justify-between px-4 sm:px-6 py-4 border-b border-slate-800">
            <h2 className="text-sm font-semibold text-slate-200">Recent Items</h2>
            <Link to="/inventory" className="text-xs text-cyan-400 hover:text-cyan-300 transition-colors">
              View all →
            </Link>
          </div>
          {/* Horizontal scroll on mobile */}
          <div className="overflow-x-auto">
            <table className="min-w-full text-sm">
              <thead>
                <tr className="text-xs uppercase tracking-widest text-slate-500 border-b border-slate-800">
                  <th className="px-4 sm:px-6 py-3 text-left font-medium whitespace-nowrap">Name</th>
                  <th className="px-4 sm:px-6 py-3 text-left font-medium whitespace-nowrap">Category</th>
                  <th className="px-4 sm:px-6 py-3 text-left font-medium whitespace-nowrap">Stock</th>
                  <th className="px-4 sm:px-6 py-3 text-left font-medium whitespace-nowrap">Location</th>
                </tr>
              </thead>
              <tbody>
                {stats.recentItems.map((item) => (
                  <tr key={item.id} className="border-t border-slate-800 hover:bg-slate-800/50 transition-colors">
                    <td className="px-4 sm:px-6 py-3">
                      <Link
                        to={`/inventory/${item.id}`}
                        className="text-slate-200 hover:text-cyan-400 transition-colors font-medium whitespace-nowrap"
                      >
                        {item.name}
                      </Link>
                    </td>
                    <td className="px-4 sm:px-6 py-3 text-slate-400 whitespace-nowrap">{catName(item.category_id)}</td>
                    <td className="px-4 sm:px-6 py-3 whitespace-nowrap"><StatusPill count={item.stock_count} /></td>
                    <td className="px-4 sm:px-6 py-3 text-slate-400 whitespace-nowrap">{item.location}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Restock Alerts */}
        <div className="rounded-2xl border border-slate-800 bg-slate-900 overflow-hidden">
          <div className="px-4 sm:px-6 py-4 border-b border-slate-800">
            <h2 className="text-sm font-semibold text-slate-200">Restock Alerts</h2>
            <p className="text-xs text-slate-500 mt-0.5">Items with stock &lt; 10</p>
          </div>
          <div className="divide-y divide-slate-800">
            {stats.lowStockItems.length === 0 ? (
              <p className="px-4 sm:px-6 py-4 text-sm text-slate-500">All levels healthy ✓</p>
            ) : (
              stats.lowStockItems.map((item) => (
                <div key={item.id} className="px-4 sm:px-6 py-4 hover:bg-slate-800/50 transition-colors">
                  <Link
                    to={`/inventory/${item.id}`}
                    className="text-sm font-medium text-slate-200 hover:text-cyan-400 transition-colors block truncate"
                  >
                    {item.name}
                  </Link>
                  <div className="flex items-center justify-between mt-1">
                    <span className="text-xs text-slate-500 truncate mr-2">{item.location}</span>
                    <span className="text-xs font-semibold text-rose-300 flex-shrink-0">{item.stock_count} left</span>
                  </div>
                  <div className="mt-2 h-1.5 rounded-full bg-slate-800 overflow-hidden">
                    <div
                      className="h-full rounded-full bg-rose-500 transition-all"
                      style={{ width: `${Math.min((item.stock_count / 10) * 100, 100)}%` }}
                    />
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
